use std::future::Future;

trait AsyncRepository {
    fn find(&self, id: u64) -> impl Future<Output = Option<String>> + Send;
    fn save(&self, id: u64, data: &str) -> impl Future<Output = Result<(), String>> + Send;
}

struct MockRepository {
    data: std::collections::HashMap<u64, String>,
}

impl MockRepository {
    fn with_data(data: Vec<(u64, &str)>) -> Self {
        MockRepository {
            data: data.into_iter().map(|(k, v)| (k, v.to_string())).collect(),
        }
    }
}

impl AsyncRepository for MockRepository {
    async fn find(&self, id: u64) -> Option<String> {
        self.data.get(&id).cloned()
    }

    async fn save(&self, _id: u64, _data: &str) -> Result<(), String> {
        Ok(())
    }
}

async fn get_or_default(repo: &impl AsyncRepository, id: u64) -> String {
    repo.find(id).await.unwrap_or_else(|| "default".to_string())
}

#[tokio::test]
async fn test_get_existing() {
    let repo = MockRepository::with_data(vec![(1, "Alice")]);
    let result = get_or_default(&repo, 1).await;
    assert_eq!(result, "Alice");
}

#[tokio::test]
async fn test_get_missing() {
    let repo = MockRepository::with_data(vec![]);
    let result = get_or_default(&repo, 99).await;
    assert_eq!(result, "default");
}

use tokio::sync::mpsc;
use std::sync::Arc;
use tokio::sync::Mutex;

async fn producer(tx: mpsc::Sender<i32>, items: Vec<i32>) {
    for item in items {
        tx.send(item).await.unwrap();
    }
}

async fn consumer(mut rx: mpsc::Receiver<i32>) -> Vec<i32> {
    let mut received = Vec::new();
    while let Some(item) = rx.recv().await {
        received.push(item);
    }
    received
}

#[tokio::test]
async fn test_producer_consumer() {
    let (tx, rx) = mpsc::channel(10);

    let producer_handle = tokio::spawn(producer(tx, vec![1, 2, 3, 4, 5]));
    let consumer_handle = tokio::spawn(consumer(rx));

    producer_handle.await.unwrap();
    let received = consumer_handle.await.unwrap();

    assert_eq!(received, vec![1, 2, 3, 4, 5]);
}
